{"code": "import json

# Load metadata for 2015 articles
metadata_file = locals()['var_functions.query_db:4']
with open(metadata_file, 'r') as f:
    metadata_2015 = json.load(f)

# Create article_id -> region mapping
article_regions = {}
for item in metadata_2015:
    article_regions[item['article_id']] = item['region']

# Get all article IDs
all_ids = list(article_regions.keys())
print('__RESULT__:')
print(json.dumps({
    'total_articles': len(all_ids),
    'sample_regions': {k: article_regions[k] for k in list(article_regions.keys())[:5]}
}))"}

